            var filters = new List<FilterParameter>();
            var allowedCols = AllowedColumns[tableName];

            // Filters come as query parameters in format: filter_ColumnName_Operator=Value
            // e.g., filter_Region_eq=West or filter_Amount_gt=100
            var operatorMap = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
            {
                { "eq", "=" },
                { "neq", "!=" },
                { "lt", "<" },
                { "gt", ">" },
                { "lte", "<=" },
                { "gte", ">=" },
                { "like", "LIKE" }
            };

            foreach (var key in req.Query.Keys)
            {
                if (!key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                var parts = key.Split('_');
                if (parts.Length != 3)
                {
                    log.LogWarning("Invalid filter format: {FilterKey}. Expected format: filter_ColumnName_Operator", key);
                    return null;
                }

                string columnName = parts[1];
                string operatorAlias = parts[2];

                // Validate column name against whitelist
                if (!allowedCols.Contains(columnName))
                {
                    log.LogWarning("Disallowed column name in filter: {ColumnName} for table {TableName}", columnName, tableName);
                    return null;
                }

                // Map operator alias to SQL operator
                if (!operatorMap.TryGetValue(operatorAlias, out string sqlOperator))
                {
                    log.LogWarning("Invalid operator alias: {OperatorAlias}", operatorAlias);
                    return null;
                }

                // Get canonical column name from whitelist
                string safeColumnName = allowedCols.First(c => c.Equals(columnName, StringComparison.OrdinalIgnoreCase));

                string value = req.Query[key];
                if (string.IsNullOrEmpty(value))
                {
                    log.LogWarning("Empty value for filter: {FilterKey}", key);
                    return null;
                }

                // For LIKE operator, wrap value with wildcards if not already present
                if (sqlOperator == "LIKE" && !value.Contains('%'))
                {
                    value = $"%{value}%";
                }

                filters.Add(new FilterParameter
                {
                    ColumnName = safeColumnName,
                    Operator = sqlOperator,
                    Value = value
                });
            }

            return filters;
        }

        private static List<string> ParseSelectColumns(HttpRequest req, string tableName, ILogger log)
        {
            var allowedCols = AllowedColumns[tableName];
            string columnsParam = req.Query["columns"];

            if (string.IsNullOrWhiteSpace(columnsParam))
            {
