            }

            // Format: sort=ColumnName:ASC,ColumnName2:DESC
            var sortParts = sortParam.Split(',', StringSplitOptions.RemoveEmptyEntries);

            foreach (var part in sortParts)
            {
                var sortComponents = part.Trim().Split(':');
                if (sortComponents.Length != 2)
                {
                    log.LogWarning("Invalid sort format: {SortPart}. Expected format: ColumnName:ASC|DESC", part);
                    return null;
                }

                string columnName = sortComponents[0].Trim();
