        private static (string query, List<SqlParameter> parameters) BuildParameterizedQuery(
            string tableName,
            List<string> selectColumns,
            List<FilterParameter> filters,
            List<SortParameter> sortParams,
            int pageNumber,
            int pageSize)
        {
            var parameters = new List<SqlParameter>();

            // Build SELECT clause using validated/whitelisted column names (safe to use directly)
            // Column names are guaranteed to come from AllowedColumns whitelist, so bracket-quoting is safe
            string columnList = string.Join(", ", selectColumns.Select(c => $"[{c}]"));

            // Table name is from AllowedTables whitelist, safe to use with bracket quoting
            string query = $"SELECT {columnList} FROM [{tableName}]";

            // Build WHERE clause with parameterized values
            if (filters.Count > 0)
            {
                var whereClauses = new List<string>();
                for (int i = 0; i < filters.Count; i++)
                {
                    var filter = filters[i];
                    string paramName = $"@p{i}";

                    // Column name and operator are validated against whitelists
                    whereClauses.Add($"[{filter.ColumnName}] {filter.Operator} {paramName}");

                    var sqlParam = new SqlParameter(paramName, filter.Value);
                    parameters.Add(sqlParam);
                }

                query += " WHERE " + string.Join(" AND ", whereClauses);
            }

            // Build ORDER BY clause using validated column names and directions
            if (sortParams.Count > 0)
            {
                var orderClauses = sortParams.Select(s => $"[{s.ColumnName}] {s.Direction}");
                query += " ORDER BY " + string.Join(", ", orderClauses);
            }
            else
            {
                // Default ordering required for OFFSET/FETCH
                query += " ORDER BY (SELECT NULL)";
            }

            // Add pagination using OFFSET/FETCH with parameters
            int offset = (pageNumber - 1) * pageSize;
            query += " OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY";

            parameters.Add(new SqlParameter("@offset", SqlDbType.Int) { Value = offset });
            parameters.Add(new SqlParameter("@pageSize", SqlDbType.Int) { Value = pageSize });

            return (query, parameters);
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string query,
            List<SqlParameter> parameters,
            ILogger log)
        {
            var results = new List<Dictionary<string, object>>();

            // Connection string should be stored in Azure Key Vault or App Settings
            // and accessed via environment variable - never hardcoded
            string connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            if (string.IsNullOrEmpty(connectionString))
            {
